CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" varchar not null, "queue" varchar not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "pelanggans" ("id" integer primary key autoincrement not null, "user_id" integer not null, "no_hp" varchar not null, "alamat" text not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "teknisis" ("id" integer primary key autoincrement not null, "nama" varchar not null, "no_hp" varchar not null, "spesialisasi" varchar not null, "status_aktif" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
INSERT INTO teknisis VALUES(1,'zikri','0856778752627','laptop',1,'2026-06-02 16:12:51','2026-06-02 16:12:51');
CREATE TABLE IF NOT EXISTS "servis" ("id" integer primary key autoincrement not null, "kode_servis" varchar not null, "pelanggan_id" integer not null, "teknisi_id" integer, "nama_perangkat" varchar not null, "jenis_kerusakan" text not null, "status" varchar not null default 'antri', "estimasi_biaya" numeric not null, "biaya_final" numeric, "catatan_teknisi" text, "tgl_masuk" datetime not null default CURRENT_TIMESTAMP, "tgl_estimasi_selesai" date not null, "tgl_selesai" datetime, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("pelanggan_id") references "pelanggans"("id") on delete cascade, foreign key("teknisi_id") references "teknisis"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "riwayat_status" ("id" integer primary key autoincrement not null, "servis_id" integer not null, "status_lama" varchar, "status_baru" varchar not null, "catatan" text, "changed_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("servis_id") references "servis"("id") on delete cascade, foreign key("changed_by") references "users"("id") on delete cascade);
